use std::path::{Path, PathBuf};

/// Convolution sidecar artifact generated by the Room EQ pipeline.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) enum ConvolutionArtifactKind {
    Fir,
    ResidualFir,
    ExcessPhaseFir,
    PhaseCorrection,
    BandFir,
}

impl ConvolutionArtifactKind {
    fn suffix(self) -> &'static str {
        match self {
            Self::Fir => "fir",
            Self::ResidualFir => "residual_fir",
            Self::ExcessPhaseFir => "excess_phase_fir",
            Self::PhaseCorrection => "phase_correction",
            Self::BandFir => "band_fir",
        }
    }
}

pub(crate) fn convolution_artifact_filename(
    channel_name: &str,
    kind: ConvolutionArtifactKind,
    sample_rate: f64,
) -> String {
    let sample_rate = sample_rate.round().max(1.0) as u32;
    format!(
        "{}_{}_{}hz.wav",
        sanitize_filename_part(channel_name),
        kind.suffix(),
        sample_rate
    )
}

pub(crate) fn reserve_convolution_artifact_path(
    output_dir: &Path,
    channel_name: &str,
    kind: ConvolutionArtifactKind,
    sample_rate: f64,
) -> (String, PathBuf) {
    let filename = convolution_artifact_filename(channel_name, kind, sample_rate);
    let path = output_dir.join(&filename);
    if !path.exists() {
        return (filename, path);
    }

    let stem = filename.trim_end_matches(".wav");
    for suffix in 2.. {
        let candidate = format!("{stem}_{suffix:03}.wav");
        let path = output_dir.join(&candidate);
        if !path.exists() {
            return (candidate, path);
        }
    }

    unreachable!("unbounded numeric suffix search must return a filename")
}

fn sanitize_filename_part(input: &str) -> String {
    let mut out = String::with_capacity(input.len());
    let mut last_was_separator = false;

    for ch in input.chars() {
        let replacement = if ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_') {
            Some(ch)
        } else {
            Some('_')
        };

        if let Some(ch) = replacement {
            if ch == '_' {
                if !last_was_separator && !out.is_empty() {
                    out.push(ch);
                }
                last_was_separator = true;
            } else {
                out.push(ch);
                last_was_separator = false;
            }
        }
    }

    while out.ends_with('_') {
        out.pop();
    }

    if out.is_empty() {
        "channel".to_string()
    } else {
        out
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn convolution_artifact_filename_includes_sample_rate() {
        assert_eq!(
            convolution_artifact_filename("Front Left", ConvolutionArtifactKind::Fir, 96_000.0),
            "Front_Left_fir_96000hz.wav"
        );
        assert_eq!(
            convolution_artifact_filename(
                "LFE/Sub",
                ConvolutionArtifactKind::PhaseCorrection,
                44_100.0,
            ),
            "LFE_Sub_phase_correction_44100hz.wav"
        );
    }

    #[test]
    fn reserve_convolution_artifact_path_avoids_existing_files() {
        let dir = tempfile::tempdir().unwrap();
        let existing = dir.path().join("L_fir_96000hz.wav");
        std::fs::write(&existing, b"old").unwrap();

        let (filename, path) = reserve_convolution_artifact_path(
            dir.path(),
            "L",
            ConvolutionArtifactKind::Fir,
            96_000.0,
        );

        assert_eq!(filename, "L_fir_96000hz_002.wav");
        assert_eq!(path, dir.path().join("L_fir_96000hz_002.wav"));
    }
}
